SELECT t.task_id, t.project_id, p.project_name, t.task_title, t.task_status, t.priority, t.assignee_user_id, t.start_date, t.due_date, t.progress_rate, m.milestone_name FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN schedule_milestone m ON m.milestone_id = t.milestone_id
AND ( t.assignee_user_id = #{viewer_user_id} OR p.owner_user_id = #{viewer_user_id} OR EXISTS ( SELECT 1 FROM schedule_project_member pm WHERE pm.project_id = t.project_id AND pm.user_id = #{viewer_user_id} ) )
AND t.project_id = #{project_id}
AND t.assignee_user_id = #{assignee_user_id}
AND t.task_status = #{task_status}
AND ( t.task_title ILIKE CONCAT('%', #{keyword}, '%') OR p.project_name ILIKE CONCAT('%', #{keyword}, '%') )
ORDER BY t.due_date NULLS LAST, t.task_id DESC

SELECT t.task_id, t.project_id, p.project_name, t.task_title, t.task_status, t.priority, t.assignee_user_id, t.start_date, t.due_date, t.progress_rate, t.description, t.milestone_id, m.milestone_name, t.created_at, t.updated_at FROM schedule_task t INNER JOIN schedule_project p ON p.project_id = t.project_id LEFT JOIN schedule_milestone m ON m.milestone_id = t.milestone_id
AND t.task_id = #{task_id}
AND ( t.assignee_user_id = #{viewer_user_id} OR p.owner_user_id = #{viewer_user_id} OR EXISTS ( SELECT 1 FROM schedule_project_member pm WHERE pm.project_id = t.project_id AND pm.user_id = #{viewer_user_id} ) )
